* 简单工厂模式package mainimport (    &quot;fmt&quot;)type Operater interface &#123;    Operate(int, int) int&#125;type AddOperate struct &#123;&#125;func (this *AddOperate) Operate(rhs int, lhs int) int &#123;    return rhs + lhs&#125;type MultipleOperate struct &#123;&#125;func (this *MultipleOperate) Operate(rhs int, lhs int) int &#123;    return rhs * lhs&#125;type OperateFactory struct &#123;&#125;func NewOperateFactory() *OperateFactory &#123;    return &amp;OperateFactory&#123;&#125;&#125;func (this *OperateFactory) CreateOperate(operatename string) Operater &#123;    switch operatename &#123;    case &quot;+&quot;:        return &amp;AddOperate&#123;&#125;    case &quot;*&quot;:        return &amp;MultipleOperate&#123;&#125;    default:        panic(&quot;无效运算符号&quot;)        return nil    &#125;&#125;func main() &#123;    Operator := NewOperateFactory().CreateOperate(&quot;+&quot;)    fmt.Printf(&quot;add result is %d\n&quot;, Operator.Operate(1, 2))&#125;

* 工厂方法package mainimport (    &quot;fmt&quot;)type Operation struct &#123;    a float64    b float64&#125;type OperationI interface &#123;    GetResult() float64    SetA(float64)    SetB(float64)&#125;func (op *Operation) SetA(a float64) &#123;    op.a = a&#125;func (op *Operation) SetB(b float64) &#123;    op.b = b&#125;type AddOperation struct &#123;    Operation&#125;func (this *AddOperation) GetResult() float64 &#123;    return this.a + this.b&#125;type SubOperation struct &#123;    Operation&#125;func (this *SubOperation) GetResult() float64 &#123;    return this.a - this.b&#125;type MulOperation struct &#123;    Operation&#125;func (this *MulOperation) GetResult() float64 &#123;    return this.a * this.b&#125;type DivOperation struct &#123;    Operation&#125;func (this *DivOperation) GetResult() float64 &#123;    return this.a / this.b&#125;type IFactory interface &#123;    CreateOperation() Operation&#125;type AddFactory struct &#123;&#125;func (this *AddFactory) CreateOperation() OperationI &#123;    return &amp;(AddOperation&#123;&#125;)&#125;type SubFactory struct &#123;&#125;func (this *SubFactory) CreateOperation() OperationI &#123;    return &amp;(SubOperation&#123;&#125;)&#125;type MulFactory struct &#123;&#125;func (this *MulFactory) CreateOperation() OperationI &#123;    return &amp;(MulOperation&#123;&#125;)&#125;type DivFactory struct &#123;&#125;func (this *DivFactory) CreateOperation() OperationI &#123;    return &amp;(DivOperation&#123;&#125;)&#125;func main() &#123;    fac := &amp;(AddFactory&#123;&#125;)    oper := fac.CreateOperation()    oper.SetA(1)    oper.SetB(2)    fmt.Println(oper.GetResult())&#125;



* 抽象工厂方法package mainimport &quot;fmt&quot;type GirlFriend struct &#123;    nationality string    eyesColor   string    language    string&#125;type AbstractFactory interface &#123;    CreateMyLove() GirlFriend&#125;type IndianGirlFriendFactory struct &#123;&#125;type KoreanGirlFriendFactory struct &#123;&#125;func (a IndianGirlFriendFactory) CreateMyLove() GirlFriend &#123;    return GirlFriend&#123;&quot;Indian&quot;, &quot;Black&quot;, &quot;Hindi&quot;&#125;&#125;func (a KoreanGirlFriendFactory) CreateMyLove() GirlFriend &#123;    return GirlFriend&#123;&quot;Korean&quot;, &quot;Brown&quot;, &quot;Korean&quot;&#125;&#125;func getGirlFriend(typeGf string) GirlFriend &#123;    var gffact AbstractFactory    switch typeGf &#123;    case &quot;Indian&quot;:        gffact = IndianGirlFriendFactory&#123;&#125;        return gffact.CreateMyLove()    case &quot;Korean&quot;:        gffact = KoreanGirlFriendFactory&#123;&#125;        return gffact.CreateMyLove()    &#125;    return GirlFriend&#123;&#125;&#125;func main() &#123;    a := getGirlFriend(&quot;Indian&quot;)    fmt.Println(a.eyesColor)&#125;

添加字段id,并将其设置为主键自增

alter table TABLE_NAME add id int not null primary key Auto_increment

如果想添加已经有了一列为主键，可以用：

alter table TABLE_NAME add primary key(COL_NAME);

如果想修改一列为主键，则需要先删除原来的主键：


alter table TABLE_NAME drop primary key;
再重新添加主键：

alter table TABLE_NAME add primary key(COL_NAME);

在设计数据库的时候不小心将数据库的字段设置成了其内置的保留字，例如下面的这段：

CREATE TABLE IF NOT EXISTS `test_billing` (`vendor` varchar(255),`cn` varchar(255),`current_date` varchar(255),`cost` varchar(255)) ENGINE=InnoDB DEFAULT CHARSET=utf8;


这样你在执行类似下面的查询时：

select cn, cost from test_billing where current_date like&quot;2018-10%&quot;;

返回值中什么都没有，还带了一个warning：
Empty set, 1 warning (0.00 sec)

原因就是字段current_date与MySQL内置的保留字冲突了，那么这时候你还急需查看这些数据，比较快的方法就是：在冲突字段上加反引号 current_date,即
select cn, cost from test_billing where `current_date` like&quot;2018-10%&quot;;

就可以解决了。

以下是我最近在 Go 中学到的 5 个小技巧，感觉挺有用且容易被大家忽略，在这里分享给大家。
计算数组元素的活可以交给编译器在 Go 中，数组的使用并不多，大家都会选择使用 slice。在使用 slice 时，如果不想自己写数组中元素的个数，可以使用 […] ，编译器会帮你计数：
package mainimport &quot;fmt&quot;func main() &#123;    arr := [3]int&#123;1, 2, 3&#125;    sameArr := [...]int&#123;1, 2, 3&#125; // Use ... instead of 3    // Arrays are equivalent    fmt.Println(arr)    fmt.Println(sameArr)&#125;

使用 go run .代替 go run main.go每当我开始用 Go 创建项目时，我都会先创建一个 main.go 文件：
package mainimport &quot;fmt&quot;func main() &#123;    sayHello()&#125;func sayHello() &#123;    fmt.Println(&quot;Hello!&quot;)&#125;

但当 main.go 文件变大时，就要使用同一个 main 将结构体分割到多个文件。但是，如果我有以下文件：
main.go
package mainfunc main() &#123;    sayHello()&#125;

say_hello.go
package mainimport &quot;fmt&quot;func sayHello() &#123;    fmt.Println(&quot;Hello!&quot;)&#125;

输入 go run main.go 会出现以下错误：
# command-line-arguments./main.go:4:2: undefined: sayHello
解决这个问题，需要使用  go run .
使用下划线使数字清晰易读package mainimport &quot;fmt&quot;func main() &#123;    number := 10000000    better := 10_000_000    fmt.Println(number == better)&#125;


在同一个包中使用不同的 test package之前以为每个文件夹只能有一个 go package。后来发现对于名为 yourpackage 的包，你可以在同一目录下拥有另一个名为 yourpackage_test 的包，并在其中编写测试。为什么要这么做呢？因为这样可以使用相同的包 yourpackage 来编写测试，所以未导出的函数也会可用。通过在 yourpackage_test 中编写测试，可以确保只测试暴露的行为。
多次传递相同参数在使用字符串格式化函数时，总觉得必须重复使用多次的参数是很繁琐的事情：
package mainimport &quot;fmt&quot;func main() &#123;    name := &quot;Bob&quot;    fmt.Printf(&quot;My name is %s. Yes, you heard that right: %s\n&quot;, name, name)&#125;
还有一种更方便的方法。可以只传递一次参数，并在 %s 动词中使用 %[order]s：
package mainimport &quot;fmt&quot;func main() &#123;    name := &quot;Bob&quot;    fmt.Printf(&quot;My name is %[1]s. Yes, you heard that right: %[1]s\n&quot;, name)&#125;
希望大家今天能学到一些新东西。如果你也有一些 golang 小技巧，可以在评论区留言分享！

Golang 可以通过启动 goroutines 来并发执行任务。它们可以通过一种名为 “通道”的通信媒介相互通信。话不多说，下面我列举了几种不同情况下 channel 的使用以及其适用条件，最后总结出一张 channel table，能够帮助你快速吃透 channel 的所有要点。Let’t go!
Nil Channels如果你像创建普通变量一样创建一个通道，通道将被初始化为零值。这里要提到的另一个重要细节是，通道的发送方和接收方都必须做好通信准备，否则我们将收到一个死锁错误。这可以通过缓冲通道来避免，我们将在后面讨论。
// NOTE: Deadlockfunc nilChannel() &#123; var ch chan int// creating a goroutine and sending value on the channel go func() &#123;  ch &lt;- 1 &#125;() fmt.Println(&lt;-ch)&#125;

如果你在 main 中调用这个函数，你会得到以下错误和一些其他信息。
fatal error: all goroutines are asleep - deadlock!
这是因为我们试图在往 nil channel上发送一个值，这是坚决不允许的操作。
Empty Channel在以下代码中，我们将收到同样的死锁错误，因为我们正试图在 channel receiver 尚未准备好的通道上发送值。从下面的代码中可以看到，在接收器创建之前，值就已经在通道上发送了。
// NOTE: Deadlockfunc emptyChannel() &#123; var ch = make(chan int) ch &lt;- 1 fmt.Println(&lt;-ch)&#125;

UN Buffered Channel错误的代码已经够多了。这次让我给出一个有效的代码。在下面的代码中，我们编写了与上一个示例相同的代码，但不是创建一个 nil 通道，而是使用 make 函数创建了一个用默认值初始化的通道。 不过，如果在这种情况下没有接收器，就会错过结果，但不会产生死锁错误。
// NOTE: send single value through goroutinefunc simpleChannel() &#123; var ch = make(chan int) go func() &#123;  ch &lt;- 1 &#125;()// NOTE: if you comment this line. You will not be able to receive the result but code will not crash fmt.Println(&lt;-ch)&#125;

Channel 方向默认情况下通道是双向的。下面的代码显示了一个只能用于发送值的通道。如果我们试图从中获取值，就会出错。
func uniDirectionalChannel() &#123;// Bidirectional [outside goroutine] var ch = make(chan int) go func(ch chan&lt;- int) &#123; // unidirectinal [within goroutine]  ch &lt;- 1 &#125;(ch) fmt.Println(&lt;-ch)&#125;

Buffered Channel这些通道可以像数组一样容纳多个值，因此在非缓冲通道中，如果我们尝试在没有接收器的情况下向其写入数据，就会出错，但在缓冲通道中，我们可以向其写入数据，直到缓冲区满为止。当缓冲区已满时，如果我们尝试向其中写入新值，就会出错。如果我们这里不注释该函数的最后一行，就会出现死锁错误，因为这里将从空通道读取数据。
// using buffered channelfunc bufferdChannelWithoutLoop() &#123; var ch = make(chan int, 2) ch &lt;- 1 ch &lt;- 2 fmt.Println(&lt;-ch) fmt.Println(&lt;-ch) // fmt.Println(&lt;-ch) // NOTE: Deadlock, Reading from empty channel&#125;
从通道读取数值还有另一种方法，即使用循环。在前面的示例中，我们逐个读取数值，但我们也可以通过循环读取接收通道中的数值，因此每当通道中发送一个新数值时，循环就会迭代，执行完正文中的代码后，就会等待下一个数值。如果接收器试图读取，但通道上已没有其他值，则会出现同样的死锁错误。
开发人员的职责是在通道使用后将其关闭，因为如果接收器试图读取已经关闭的通道，就会出现上述死锁问题。
Channels Table我们已经讨论了通道的所有情况，但怎么才能快速记住它们呢？ 别紧张😎，有我在，下表可以作为快速指南，对照着表盘一下我们写的 channel 就能避免出现死锁，并显示它们在不同情况下的行为。

在上一篇文章中，我们用 C 语言创建了一个 eBPF 程序，以了解某个进程使用 CPU 的时间。这些数据随后被存储在 BPF HashMap 中。但这是一个不断更新的短期存储位置，数据的寿命很短……我们该如何利用这些数据呢？
这就是用户空间程序的用武之地。用户空间程序不在内核空间运行，但可以附加到 eBPF 程序并访问 BPF HashMap。
现在让我们来看看如何用 Golang 编写用户空间程序。
Bpf2go在使用 Golang 时，有一个很好用的工具叫做 bpf2go。这个工具可以帮助我们将之前编写的 C 代码编译成 eBPF 字节码。此外，它还能创建 Golang 函数和结构的骨架，以便我们将其接口到代码中，从而节省大量时间。
Step 1: 创建 gen.go 文件package main//go:generate go run github.com/cilium/ebpf/cmd/bpf2go processtime processtime.c
gen.go 文件中的注释行允许我们运行 go 生成，然后使用 bpf2go 工具读取 C 程序（在本例中，第二个标志是 processtime.c），并输出生成的 Golang 代码，这些代码将使用前缀 processtime（第一个标志）。运行 go 生成后，你将得到以下文件：
$ tree.|____gen.go|____processtime.c|____processtime_bpfel.o|____processtime_bpfeb.o|____processtime_bpfel.go|____processtime_bpfeb.go
这里生成了四个文件。对象文件（以 .o 结尾的文件）是将加载到内核中的 eBPF 字节码。以 Golang ext 结尾的 .go 文件是创建所有用户空间接口的文件。
打开这两个 Golang 文件，你还会发现每个文件的顶部都有一个注释，说明该文件适用于哪种 CPU 架构。例如，processtime_bpfeb.go 的注释如下：
// Code generated by bpf2go; DO NOT EDIT.//go:build arm64be || armbe || mips || mips64 || mips64p32 || ppc64 || s390 || s390x || sparc || sparc64
processtime_bpfel.go 有不同的架构：这是因为，在处理内核时，程序的编译方式在每种架构上都有细微差别。
步骤 2：编写用户空间程序我们可以开始使用 eBPF 程序了。我们将在根目录下创建一个 main.go，并首先取消资源限制：
// Remove resource limits for kernels &lt;5.11.if err := rlimit.RemoveMemlock(); err != nil &#123;  log.Fatal(&quot;Removing memlock:&quot;, err)&#125;
这是因为内核 v5.11 发生了变化，BPF 进程的可用内存过去受 RLIMIT_MEMLOCK 限制，但这一逻辑已移至内存 cgroup (memcg)。
下一步是加载 eBPF 程序。这是通过 bpf2go 工具生成的接口代码中的一个名为 loadProcesstimeObject 的函数完成的。我们需要创建一个变量来存储该函数调用的输出。
// Load the compiled eBPF ELF into the kernel.var objs processtimeObjectsif err := loadProcesstimeObjects(&amp;objs, nil); err != nil &#123;  log.Fatal(&quot;Loading eBPF objects:&quot;, err)&#125;defer objs.Close()
接下来，我们需要连接到已加载的程序。这就需要知道你挂接的是什么事件，因为你需要指定它。在我们的 C 程序中，我们指定了以下内容：
SEC(&quot;tracepoint/sched/sched_switch&quot;)
因此，我们知道我们的程序挂接到了 sched 命名空间中的跟踪点 sched_switch。这可以转化为以下内容：
// link to the tracepoint program that we loaded into the kerneltp, err := link.Tracepoint(&quot;sched&quot;, &quot;sched_switch&quot;, objs.CpuProcessingTime, nil)if err != nil &#123;  log.Fatalf(&quot;opening kprobe: %s&quot;, err)&#125;defer tp.Close()
我们需要的最后一项功能是读取存储在 BPF HashMap 中的数据。这可以通过使用 HashMap 的键来查看存储的值。在生成 Golang 代码时，我们生成了两种类型来帮助我们与 BPF HashMap 交互。
// used as HashMap Keytype processtimeKeyT struct&#123; Pid uint32 &#125;// used as HashMap Valuetype processtimeValT struct &#123;  StartTime uint64  ElapsedTime uint64&#125;
这与我们在 C 程序中使用的两种类型相关：
// used as Hashmap Keystruct key_t &#123;__u32 pid;&#125;;// used as Hashmap Valuestruct val_t &#123;__u64 start_time;__u64 elapsed_time;&#125;;
在我们的例子中，键值基本上就是进程 ID。现在，在大多数系统中，PID 的默认值介于 1 和 32767 之间，但你可以通过查看 &#x2F;proc&#x2F;sys&#x2F;kernel&#x2F;pid_max 文件来查看该值。
通过上述逻辑，我们应该可以遍历所有潜在的 PID，并检查 BPF HashMap，查看是否有存储的值。因此，我们可以使用它们来编写我们的循环逻辑：
var key processtimeKeyT// Iterate over all PIDs between 1 and 32767 (maximum PID on linux)// found in /proc/sys/kernel/pid_maxfor i := 1; i &lt;= 32767; i++ &#123;  key.Pid = uint32(i)  // Query the BPF map  var mapValue processtimeValT  if err := objs.ProcessTimeMap.Lookup(key, &amp;mapValue); err == nil &#123;    log.Printf(&quot;CPU time for PID=%d: %dns\n&quot;, key.Pid, mapValue.ElapsedTime)  &#125;&#125;

这段代码将循环处理每个可用的 PID，并在我们的 BPF HashMap（由 objs.ProcessTimeMap 指定）中进行查找，如果没有错误返回，将打印出值。
步骤 3.完整代码最终代码如下所示：（请注意，我有一个每秒运行一次循环的 ticker，因为 HashMap 可以不断更新，因此我们需要不断重新读取它）
package mainimport (  &quot;C&quot;  &quot;log&quot;  &quot;time&quot;  &quot;github.com/cilium/ebpf/link&quot;  &quot;github.com/cilium/ebpf/rlimit&quot;)func main() &#123;  // Remove resource limits for kernels &lt;5.11.  if err := rlimit.RemoveMemlock(); err != nil &#123;    log.Fatal(&quot;Removing memlock:&quot;, err)  &#125;  // Load the compiled eBPF ELF and load it into the kernel.  var objs processtimeObjects  if err := loadProcesstimeObjects(&amp;objs, nil); err != nil &#123;    log.Fatal(&quot;Loading eBPF objects:&quot;, err)  &#125;  defer objs.Close()  // link to the tracepoint program that we loaded into the kernel  tp, err := link.Tracepoint(&quot;sched&quot;, &quot;sched_switch&quot;, objs.CpuProcessingTime, nil)  if err != nil &#123;    log.Fatalf(&quot;opening kprobe: %s&quot;, err)  &#125;  defer tp.Close()  // Read loop reporting the total amount of times the kernel  // function was entered, once per second.  ticker := time.NewTicker(1 * time.Second)  defer ticker.Stop()  log.Println(&quot;Waiting for events..&quot;)  for range ticker.C &#123;    var key processtimeKeyT    // Iterate over all PIDs between 1 and 32767 (maximum PID on linux)    // found in /proc/sys/kernel/pid_max    for i := 1; i &lt;= 32767; i++ &#123;      key.Pid = uint32(i)      // Query the BPF map      var mapValue processtimeValT      if err := objs.ProcessTimeMap.Lookup(key, &amp;mapValue); err == nil &#123;        log.Printf(&quot;CPU time for PID=%d: %dns\n&quot;, key.Pid, mapValue.ElapsedTime)      &#125;    &#125;  &#125;&#125;

总结eBPF 是一项值得关注的技术。它在网络、可观测性和安全性方面能够发挥重要作用。了解基本原理是第一步，但要深入研究的东西还有很多。可以期待后续的文章分享👀。
